def solve(indicator_type, original_value, original_unit, target_unit):
    # Step 1: Convert lipid indicator value between mmol/L and mg/dL according to indicator type.
    if indicator_type in ("TC", "HDL-C", "LDL-C"):
        if original_unit == "mmol/L" and target_unit == "mg/dL":
            converted_value = original_value * 38.67
        elif original_unit == "mg/dL" and target_unit == "mmol/L":
            converted_value = original_value * 0.02586
        else:
            converted_value = original_value
    elif indicator_type == "TG":
        if original_unit == "mmol/L" and target_unit == "mg/dL":
            converted_value = original_value * 88.57
        elif original_unit == "mg/dL" and target_unit == "mmol/L":
            converted_value = original_value * 0.01129
        else:
            converted_value = original_value
    else:
        raise ValueError("indicator_type must be one of: 'TC', 'HDL-C', 'LDL-C', 'TG'")

    yield {
        "step_name": "convert_lipid_unit",
        "step_description": "Convert lipid indicator value between mmol/L and mg/dL according to indicator type.",
        "step_result": converted_value,
        "unit": target_unit
    }

    return converted_value
